LOG_FILE = Path(__file__).resolve().parent / "run_dashboard.log"
def log(msg: str) -> None:
    LOG_FILE.parent.mkdir(parents=True, exist_ok=True)
    ts = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    line = f"[{ts}] {msg}"
    print(line, flush=True)
    with open(LOG_FILE, "a", encoding="utf-8") as f:
        f.write(line + "\n")


def _ensure_required_packages() -> None:
    """Install required third-party packages on first local run if missing."""
    import importlib

    required = [
        ("streamlit", "streamlit"),
        ("pandas", "pandas"),
        ("plotly", "plotly"),
        ("matplotlib", "matplotlib"),
        ("PIL", "Pillow"),
        ("openpyxl", "openpyxl"),
    ]
    missing: list[str] = []
    for module_name, package_name in required:
        try:
            importlib.import_module(module_name)
        except Exception:
            missing.append(package_name)

    if not missing:
        log("all required packages already installed")
        return

    unique_missing: list[str] = []
    for pkg in missing:
        if pkg not in unique_missing:
            unique_missing.append(pkg)

    log(f"missing packages detected: {', '.join(unique_missing)}")
    cmd = [sys.executable, "-m", "pip", "install", *unique_missing]
    log(f"install command: {' '.join(cmd)}")
    subprocess.check_call(cmd, cwd=str(Path(__file__).resolve().parent))
    log("package installation completed")



def _ensure_streamlit_local_config() -> None:
    """Prevent first-run Streamlit email/usage-stats prompt for local users."""
    local_cfg_dir = Path(__file__).resolve().parent / ".streamlit"
    local_cfg_dir.mkdir(parents=True, exist_ok=True)
    config_path = local_cfg_dir / "config.toml"

    desired_block = "[browser]\ngatherUsageStats = false\n"
    if config_path.exists():
        existing = config_path.read_text(encoding="utf-8")
        if "gatherUsageStats" in existing:
            return
        if existing.strip():
            existing = existing.rstrip() + "\n\n" + desired_block
        else:
            existing = desired_block
        config_path.write_text(existing, encoding="utf-8")
    else:
        config_path.write_text(desired_block, encoding="utf-8")

def _pause():
    try:
        input("작업이 끝났습니다. Enter 키를 누르면 종료합니다...")
    except Exception:
        try:
            os.system("pause")
        except Exception:
            pass
if __name__ == "__main__" and os.environ.get("GMP_ENABLE_LOCAL_LAUNCHER") == "1" and os.environ.get("GMP_DASHBOARD_CHILD") != "1":
    log("START dashboard launcher")
    try:
        _ensure_required_packages()
        _ensure_streamlit_local_config()
        env = os.environ.copy()
        env["STREAMLIT_BROWSER_GATHER_USAGE_STATS"] = "false"
        env["GMP_DASHBOARD_CHILD"] = "1"
        cmd = [sys.executable, "-m", "streamlit", "run", str(Path(__file__).resolve())]
        log(f"launch command: {' '.join(cmd)}")
        subprocess.Popen(cmd, cwd=str(Path(__file__).resolve().parent), env=env)
        log("dashboard subprocess started")
    except Exception as e:
        log(f"dashboard launch failed: {e}")
        log(traceback.format_exc())
    _pause()
    raise SystemExit(0)
