def _normalize_topic_text(value: str) -> str:
    return re.sub(r"\s+", "", str(value or "")).strip().lower()

def _summary_contains(summary: str, *needles: str) -> bool:
    compact = _normalize_topic_text(summary)
    return all(_normalize_topic_text(n) in compact for n in needles if n)


def _topic_override(field: str, summary: str, ref1: str, ref2: str) -> str:
    s = normalize_summary_for_grouping(summary)
    compact = _normalize_topic_text(s)
    r1 = _normalize_topic_text(ref1)
    r2 = _normalize_topic_text(ref2)

    def has(*words: str) -> bool:
        return all(_normalize_topic_text(w) in compact for w in words if w)

