SUMMARY_TOKEN_STOPWORDS = {"관리", "관련", "대한", "실시", "미흡", "부적절", "확인", "기준", "절차", "기록", "작성", "운영", "점검", "실시하지", "않음", "제조", "시험", "평가", "자료", "사항", "지적", "실태조사", "결과", "업무", "사용", "실제", "수행", "필요", "있음"}
def _clean_example_text(s: str, limit: int = 34) -> str:
    s = normalize_summary_for_grouping(s)
    s = re.sub(r"\s+", " ", s).strip(" .,")
    if len(s) > limit:
        return s[:limit].rstrip() + "…"
    return s
def _extract_signal_keywords(texts, topn: int = 3, exclude: set[str] | None = None) -> list[str]:
    exclude = exclude or set()
    counts = {}
    for text in texts:
        text = normalize_summary_for_grouping(text)
        tokens = re.findall(r"[가-힣A-Za-z0-9/]+", text)
        seen = set()
        for tok in tokens:
            tok = tok.strip("/")
            if len(tok) < 2 or tok in SUMMARY_TOKEN_STOPWORDS or tok in seen or tok in exclude:
                continue
            seen.add(tok)
            counts[tok] = counts.get(tok, 0) + 1
    ranked = sorted(counts.items(), key=lambda x: (-x[1], -len(x[0]), x[0]))
    return [tok for tok, _ in ranked[:topn]]
def _extra_topic_keywords(topic_counts: pd.Series, used_topics: list[str], topn: int = 2) -> list[str]:
    extras = []
    for topic, _ in list(topic_counts.items())[len(used_topics):]:
        topic = str(topic).strip()
        if topic and topic not in extras:
            extras.append(topic)
        if len(extras) >= topn:
            break
    return extras
def _overall_theme_text(topic_counts: pd.Series) -> str:
    bucket_scores = {}
    for topic, cnt in topic_counts.items():
        for bucket, topics in TOPIC_META_BUCKETS.items():
            if topic in topics:
                bucket_scores[bucket] = bucket_scores.get(bucket, 0) + int(cnt)
    if not bucket_scores:
        return "지적은 개별 문장보다 운영기준과 실제 실행 사이의 간극이 누적된 흐름으로 보입니다."
    phrases = {
        "문서기록": "문서·기록 체계",
        "변경일탈후속": "변경·일탈 후속관리",
        "설비환경운영": "설비·환경 운영관리",
        "공급자원자재": "공급자·원자재 관리",
        "밸리데이션공정": "밸리데이션·공정관리",
    }
    ordered = [k for k, _ in sorted(bucket_scores.items(), key=lambda x: -x[1])[:2]]
    labels = [phrases.get(x, x) for x in ordered]
    if len(labels) == 1:
        return f"특히 {labels[0]} 축의 반복 지적이 두드러져, 개별 항목을 따로 보완하기보다 관련 기준과 운영방식을 함께 손보는 편이 더 적절해 보입니다."
    return f"특히 {labels[0]}와 {labels[1]} 축의 지적이 함께 나타나, 개별 항목을 따로 고치기보다 서로 맞물린 관리 흐름을 함께 정비하는 편이 더 적절해 보입니다."
def _field_trend_sentence(field: str, sub: pd.DataFrame, total: int) -> str:
    count = int(len(sub))
    share = (count / total * 100) if total else 0.0
    topic_counts = sub["주제그룹"].value_counts()
    top_items = list(topic_counts.head(3).items())
    dominant, dominant_count = top_items[0]
    dominant_share = dominant_count / count * 100 if count else 0.0
    second = top_items[1][0] if len(top_items) > 1 else ""
    third = top_items[2][0] if len(top_items) > 2 else ""
    top3_share = sum(cnt for _, cnt in top_items) / count * 100 if count else 0.0
    dominant_rows = sub[sub["주제그룹"] == dominant]["지적사항 요약"].astype(str).tolist()
    second_rows = sub[sub["주제그룹"] == second]["지적사항 요약"].astype(str).tolist() if second else []
    example1 = _clean_example_text(dominant_rows[0] if dominant_rows else dominant)
    example2 = _clean_example_text(second_rows[0] if second_rows else (dominant_rows[1] if len(dominant_rows) > 1 else ""))
    extra_topics = _extra_topic_keywords(topic_counts, [x[0] for x in top_items], topn=2)
    extra_topic_text = ", ".join(extra_topics) if extra_topics else ""
    if dominant_share >= 55:
        spread_text = f"{dominant}가 {dominant_count}건으로 가장 큰 비중을 차지했고"
    elif top3_share >= 80:
        spread_text = f"{dominant}, {second or dominant}, {third or second or dominant} 등 상위 유형에 지적이 집중됐고"
    else:
        spread_text = f"{dominant}와 {second or third or dominant} 축이 함께 나타났고"
    interpretation = FIELD_INTERPRETATION_MAP.get(field, {}).get(dominant, "같은 관리축에서 반복 지적이 누적된 흐름")
    parts = [f"{field}는 전체의 {share:.1f}%인 {count}건이었고, {spread_text} {interpretation}으로 볼 수 있습니다."]
    if second:
        parts.append(f"세부적으로는 {dominant}({int(dominant_count)}건), {second}({int(top_items[1][1])}건)가 중심이었습니다.")
    else:
        parts.append(f"세부적으로는 {dominant} 유형이 중심이었습니다.")
    if example2:
        parts.append(f"대표 사례로는 '{example1}', '{example2}'와 같은 지적이 반복되어 관련 기준을 같은 묶음으로 정비할 필요가 있습니다.")
    else:
        parts.append(f"대표 사례로는 '{example1}'와 같은 지적이 반복되어 유사 항목을 함께 정리할 필요가 있습니다.")
    if extra_topic_text:
        parts.append(f"또한 Top5 밖에서는 {extra_topic_text} 같은 세부 항목도 함께 확인됐습니다.")
    text = " ".join(parts)
    return re.sub(r"\s+", " ", text).strip()
def build_trend_summary(df: pd.DataFrame, period_label: str) -> list[str]:
    pf = filter_by_period(df, period_label).copy()
    if pf.empty or "감시분야" not in pf.columns or "지적사항 요약" not in pf.columns:
        return ["해당 기간에는 해석 가능한 지적사항 데이터가 부족합니다."]
    pf = pf[pf["지적사항 요약"].map(is_real_finding)].copy()
    if pf.empty:
        return ["해당 기간에는 해석 가능한 지적사항 데이터가 부족합니다."]
    pf["감시분야"] = pf["감시분야"].map(normalize_field)
    pf["주제그룹"] = pf.apply(
        lambda r: infer_topic_from_row(r),
        axis=1,
    )
    total = int(len(pf))
    field_counts = pf["감시분야"].value_counts()
    topic_counts = pf["주제그룹"].value_counts()
    top_fields = [(field, int(cnt), (cnt / total * 100) if total else 0.0) for field, cnt in field_counts.items() if field in FIELD_ORDER]
    top_topics = list(topic_counts.head(4).items())
    overall_parts = [f"이번 기간 지적은 총 {total}건으로 집계되었으며,"]
    if top_fields:
        overall_parts.append(
            ", ".join([f"{field} {cnt}건({share:.1f}%)" for field, cnt, share in top_fields[:3]]) + " 순으로 비중이 높았습니다."
        )
    if top_topics:
        overall_parts.append(
            "상위 유형은 " + ", ".join([f"{topic} {int(cnt)}건" for topic, cnt in top_topics[:4]]) + "이었습니다."
        )
    overall_parts.append(_overall_theme_text(topic_counts))
    overall_line = re.sub(r"\s+", " ", " ".join(overall_parts)).strip()
    lines: list[str] = [overall_line]
    for field in FIELD_ORDER:
        sub = pf[pf["감시분야"].astype(str).str.strip() == field].copy()
        if sub.empty:
            continue
        lines.append(_field_trend_sentence(field, sub, total))
    return lines
def build_report_pdf(filtered: pd.DataFrame, period_label: str) -> bytes:
    actual, field_df, grade_df = get_count_frames(filtered)
    top5_display = build_top5_display_table(filtered, period_label)
    summary_lines = build_trend_summary(filtered, period_label)
    period_kor = format_period_label_korean(period_label)
    created_at = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    if FONT_NAME:
        rcParams["font.family"] = FONT_NAME
        rcParams["axes.unicode_minus"] = False
    margin_lr_cm = 1.0
    margin_tb_cm = 1.5
    a4_landscape = (11.69, 8.27)
    a4_portrait = (8.27, 11.69)
    def _cm_to_fig_frac(cm: float, figsize: tuple[float, float], axis: str) -> float:
        inches = cm / 2.54
        return inches / (figsize[0] if axis == "x" else figsize[1])
    def _wrap_cell(s: str, width: int = 15) -> str:
        s = str(s).strip()
        if not s:
            return ""
        words = re.split(r"\s+", s)
        lines, cur = [], ""
        for w in words:
            candidate = (cur + " " + w).strip()
            if len(candidate) <= width:
                cur = candidate
            else:
                if cur:
                    lines.append(cur)
                cur = w
        if cur:
            lines.append(cur)
        return "\n".join(lines)
    def _add_bar_labels(ax, bars):
        for bar in bars:
            height = float(bar.get_height())
            if height <= 0:
                continue
            ax.text(
                bar.get_x() + bar.get_width() / 2,
                height - max(height * 0.08, 0.35),
                f"{int(round(height))}",
                ha="center", va="top", fontsize=9, weight="bold", color="black"
            )
    def _load_logo_image():
        try:
            return Image.open(io.BytesIO(base64.b64decode(HANALL_LOGO_B64))).convert("RGBA")
        except Exception:
            return None
    def _load_symbol_image():
        try:
            return Image.open(io.BytesIO(base64.b64decode(HANALL_SYMBOL_B64))).convert("RGBA")
        except Exception:
            return None
    def _add_title_symbol(ax, x: float, y: float, w: float = 0.075):
        symbol = _load_symbol_image()
        if symbol is None:
            return
        symbol = symbol.copy()
        alpha = symbol.getchannel("A")
        alpha = alpha.point(lambda p: int(p * 0.95))
        symbol.putalpha(alpha)
        h = w * (symbol.size[1] / symbol.size[0])
        iax = ax.inset_axes([x, y - h + 0.002, w, h], transform=ax.transAxes, zorder=4)
        iax.imshow(symbol)
        iax.axis("off")
    def _draw_report_header(fig, figsize: tuple[float, float], left: float, right: float, top: float,
                            period_kor: str, period_label: str, created_at: str, title_fs: float = 18.0):
        symbol = _load_symbol_image()
        title_y = top - _cm_to_fig_frac(0.08, figsize, "y")
        meta_x = right - _cm_to_fig_frac(0.02, figsize, "x")
        if symbol is not None:
            symbol = symbol.copy().convert("RGBA")
            alpha = symbol.getchannel("A")
            alpha = alpha.point(lambda px: int(px * 0.98))
            symbol.putalpha(alpha)
            symbol_x = left + _cm_to_fig_frac(0.02, figsize, "x")
            symbol_w = _cm_to_fig_frac(1.40, figsize, "x")
            symbol_h = symbol_w * (symbol.size[1] / symbol.size[0]) * (figsize[0] / figsize[1])
            symbol_y = title_y - symbol_h * 0.78
            sax = fig.add_axes([symbol_x, symbol_y, symbol_w, symbol_h], zorder=6)
            sax.imshow(symbol)
            sax.axis("off")
            title_x = symbol_x + symbol_w + _cm_to_fig_frac(0.08, figsize, "x")
        else:
            title_x = left + _cm_to_fig_frac(0.02, figsize, "x")
        fig.text(title_x, title_y, f"식약처 의약품 GMP 실태조사 {period_kor} Letter",
                 fontsize=title_fs, weight="bold", va="top", ha="left", color="black")
        fig.text(meta_x, title_y, f"대상 기간: {period_label}\n생성일시: {created_at}",
                 fontsize=8.0 if title_fs < 17 else 7.9, color="#6E6E6E",
                 va="top", ha="right", linespacing=1.28 if title_fs >= 17 else 1.30)
    def _draw_num_box(ax, x: float, y: float, num: int, color: str, box_w: float = 0.028, box_h: float = 0.045, fs: float = 11.0):
        ax.text(
            x, y, f"{num:02d}",
            transform=ax.transAxes,
            ha="center", va="center",
            fontsize=fs, weight="bold", color="white",
            bbox=dict(boxstyle="square,pad=0.16", facecolor=color, edgecolor=color, linewidth=0.0),
            zorder=5
        )
    def _add_page_footer(fig, page_no: int, color: str = "#6E6E6E"):
        fig.text(0.985, 0.015, f"MFDS GMP Letter  |  Page {page_no}", fontsize=9.0, color=color, ha="right", va="bottom")
    def _add_center_watermark(fig, figsize: tuple[float, float], left: float, right: float, bottom: float, top: float):
        logo = _load_logo_image()
        if logo is None:
            return
        logo_rgba = logo.copy()
        alpha = logo_rgba.getchannel("A")
        alpha = alpha.point(lambda p: int(p * 0.14))
        logo_rgba.putalpha(alpha)
        avail_w = right - left
        avail_h = top - bottom
        target_w = avail_w * 0.80
        target_h = target_w * (logo_rgba.size[1] / logo_rgba.size[0]) * (figsize[0] / figsize[1])
        if target_h > avail_h * 0.40:
            target_h = avail_h * 0.40
            target_w = target_h * (logo_rgba.size[0] / logo_rgba.size[1]) * (figsize[1] / figsize[0])
        x = left + (avail_w - target_w) / 2
        y = bottom + (avail_h - target_h) / 2 - (avail_h * 0.035)
        wm_ax = fig.add_axes([x, y, target_w, target_h], zorder=0)
        wm_ax.imshow(logo_rgba)
        wm_ax.axis("off")
    def _decorate_page(fig, figsize: tuple[float, float]):
        left = _cm_to_fig_frac(margin_lr_cm, figsize, "x")
        right = 1.0 - left
        bottom = _cm_to_fig_frac(margin_tb_cm, figsize, "y")
        top = 1.0 - bottom
        _add_center_watermark(fig, figsize, left, right, bottom, top)
        return left, right, bottom, top
    def _wrap_text_to_axes(fig, ax, text_value: str, fontsize: float, x0: float = 0.01, x1: float = 0.93) -> str:
        s = re.sub(r"\s+", " ", str(text_value).strip())
        if not s:
            return ""
        fig.canvas.draw()
        renderer = fig.canvas.get_renderer()
        start_px = ax.transAxes.transform((x0, 0))[0]
        end_px = ax.transAxes.transform((x1, 0))[0]
        max_px = max(10.0, end_px - start_px)
        probe = ax.text(0, 0, "", fontsize=fontsize, alpha=0.0)
        lines, current = [], ""
        break_chars = {" ", "/", ",", "·", ")", "-"}
        last_break = -1
        for ch in s:
            candidate = current + ch
            probe.set_text(candidate)
            width = probe.get_window_extent(renderer=renderer).width
            if width <= max_px or not current:
                current = candidate
                if ch in break_chars:
                    last_break = len(current)
                continue
            if last_break > 0:
                line = current[:last_break].rstrip()
                remainder = current[last_break:].lstrip()
                lines.append(line)
                current = remainder + ch
            else:
                lines.append(current.rstrip())
                current = ch.lstrip() if ch == " " else ch
            last_break = -1
            for pos in range(len(current) - 1, -1, -1):
                if current[pos] in break_chars:
                    last_break = pos + 1
                    break
        if current.strip():
            lines.append(current.rstrip())
        probe.remove()
        return "\n".join(lines)
    def _line_count(s: str) -> int:
        return max(1, str(s).count("\n") + 1)
    category_col = next((c for c in ["1차 구분", "1차구분", "1차 분류"] if c in filtered.columns), None)
    category_df = pd.DataFrame(columns=["세부 구분", "건수"])
    if category_col is not None:
        cat_series = filtered[category_col].astype(str).str.strip()
        cat_series = cat_series[(cat_series != "") & (cat_series != "nan")]
        if not cat_series.empty:
            vc = cat_series.value_counts()
            category_df = pd.DataFrame({"1차 구분": vc.index.tolist(), "건수": vc.values.tolist()})
    buf = io.BytesIO()
    with PdfPages(buf) as pdf:
        # Page 1: summary only
        fig = plt.figure(figsize=a4_landscape)
        left, right, bottom, top = _decorate_page(fig, a4_landscape)
        content_left = left + _cm_to_fig_frac(0.18, a4_landscape, "x")
        content_right = right - _cm_to_fig_frac(0.95, a4_landscape, "x")
        content_bottom = bottom + _cm_to_fig_frac(0.18, a4_landscape, "y")
        content_top = top - _cm_to_fig_frac(0.12, a4_landscape, "y")
        ax = fig.add_axes([content_left, content_bottom, content_right - content_left, content_top - content_bottom], zorder=2)
        ax.set_facecolor("none")
        ax.axis("off")
        _draw_report_header(fig, a4_landscape, left, right, top, period_kor, period_label, created_at, title_fs=18.0)
        y = 0.905
        _draw_num_box(ax, 0.015, y - 0.012, 1, "#1EB7B5", box_w=0.03, box_h=0.045, fs=10.5)
        ax.text(0.045, y, "주요 지적사항 트렌드 요약", fontsize=14.5, weight="bold", va="top")
        y -= 0.045
        body_fs = 9.0
        line_step = 0.030
        para_gap = 0.012
        wrapped_lines = [_wrap_text_to_axes(fig, ax, f"{i}. {line}", fontsize=body_fs, x0=0.01, x1=0.925) for i, line in enumerate(summary_lines, start=1)]
        for wrapped in wrapped_lines:
            ax.text(0.01, y, wrapped, fontsize=body_fs, va="top", ha="left", linespacing=1.22, clip_on=True)
            y -= (_line_count(wrapped) * line_step) + para_gap
        _add_page_footer(fig, 1)
        pdf.savefig(fig)
        plt.close(fig)
        # Page 2: Top5 table + 1차 구분 charts (landscape)
        fig2 = plt.figure(figsize=a4_landscape)
        left2, right2, bottom2, top2 = _decorate_page(fig2, a4_landscape)
        gs2 = fig2.add_gridspec(
            3, 2,
            height_ratios=[0.13, 1.20, 0.95],
            left=left2 + _cm_to_fig_frac(0.10, a4_landscape, "x"),
            right=right2 - _cm_to_fig_frac(0.10, a4_landscape, "x"),
            top=top2 - _cm_to_fig_frac(0.10, a4_landscape, "y"),
            bottom=bottom2 + _cm_to_fig_frac(0.15, a4_landscape, "y"),
            hspace=0.30,
            wspace=0.20,
        )
        _draw_report_header(fig2, a4_landscape, left2, right2, top2, period_kor, period_label, created_at, title_fs=15.5)
        ax2_title = fig2.add_subplot(gs2[0, :])
        ax2_title.set_facecolor("none")
        ax2_title.axis("off")
        ax2_table = fig2.add_subplot(gs2[1, :])
        ax2_table.set_facecolor("none")
        ax2_table.axis("off")
        _draw_num_box(ax2_table, 0.015, 1.067, 2, "#1B73D1", box_w=0.03, box_h=0.045, fs=10.5)
        ax2_table.text(0.045, 1.05, f"감시분야별 지적사항 Top5 및 주요 현황 ({period_label})", fontsize=13.5, weight="bold", va="bottom")
        headers = ["감시분야", "Top1", "Top2", "Top3", "Top4", "Top5"]
        rows = []
        for _, row in top5_display.iterrows():
            if str(row.get("감시분야", "")).strip() in {"합계", ""}:
                continue
            rows.append([
                row.get("감시분야", ""),
                _wrap_cell(row.get("Top1", ""), 18),
                _wrap_cell(row.get("Top2", ""), 18),
                _wrap_cell(row.get("Top3", ""), 18),
                _wrap_cell(row.get("Top4", ""), 18),
                _wrap_cell(row.get("Top5", ""), 18),
            ])
        tbl = ax2_table.table(
            cellText=rows,
            colLabels=headers,
            cellLoc="center",
            colLoc="center",
            colWidths=[0.10, 0.18, 0.18, 0.18, 0.18, 0.18],
            bbox=[0, 0, 1, 0.95],
            loc="upper left",
        )
        tbl.auto_set_font_size(False)
        tbl.set_fontsize(9.6)
        tbl.scale(1.0, 2.30)
        for (r, c), cell in tbl.get_celld().items():
            cell.set_text_props(ha="center", va="center", wrap=True)
            cell.set_facecolor((1, 1, 1, 0.0))
            if r == 0:
                cell.set_text_props(weight="bold", ha="center", va="center", wrap=True)
                cell.set_height(0.11)
            else:
                cell.set_height(0.15)
        ax2_info = fig2.add_subplot(gs2[2, :])
        ax2_info.set_facecolor("none")
        ax2_info.axis("off")
        period_actual, period_summary_df, _ = build_manufacturer_dataset(filtered, period_label)
        detail_top_df = pd.DataFrame(columns=["세부구분", "건수"])
        if not period_actual.empty and "세부구분" in period_actual.columns:
            detail_series = period_actual["세부구분"].astype(str).str.strip()
            detail_series = detail_series[(detail_series != "") & (detail_series != "nan")]
            if not detail_series.empty:
                vc_detail = detail_series.value_counts().head(10)
                detail_top_df = pd.DataFrame({"세부구분": vc_detail.index.tolist(), "건수": vc_detail.values.tolist()})
        grade_company_df = pd.DataFrame(columns=["우선관리 등급", "업체 수", "해당 업체명"])
        if not period_summary_df.empty and "우선관리등급" in period_summary_df.columns:
            priority_order = ["즉시 관리 필요", "중대 이슈 관리", "지속 관리 필요", "일반 모니터링"]
            work_df = period_summary_df.copy()
            if "제조업체명" in work_df.columns:
                work_df["제조업체명"] = work_df["제조업체명"].astype(str).str.strip()
            grade_counts = work_df["우선관리등급"].astype(str).value_counts()
            ordered = [g for g in priority_order if g in grade_counts.index]
            grade_rows_data = []
            for g in ordered:
                company_names = []
                if "제조업체명" in work_df.columns:
                    company_names = (
                        work_df.loc[work_df["우선관리등급"].astype(str) == g, "제조업체명"]
                        .dropna()
                        .astype(str)
                        .str.strip()
                    )
                    company_names = [name for name in company_names.tolist() if name and name.lower() != "nan"]
                    deduped = []
                    seen = set()
                    for name in company_names:
                        if name not in seen:
                            seen.add(name)
                            deduped.append(name)
                    company_names = deduped
                display_names = ", ".join(company_names) if g in {"즉시 관리 필요", "중대 이슈 관리"} else "-"
                grade_rows_data.append({
                    "우선관리 등급": g,
                    "업체 수": int(grade_counts[g]),
                    "해당 업체명": display_names,
                })
            grade_company_df = pd.DataFrame(grade_rows_data)
        company_top_df = pd.DataFrame(columns=["제조업체명", "건수"])
        if not period_actual.empty and "제조업체명" in period_actual.columns:
            comp = period_actual["제조업체명"].astype(str).str.strip()
            comp = comp[(comp != "") & (comp != "nan")]
            if not comp.empty:
                vc_comp = comp.value_counts().head(10)
                company_top_df = pd.DataFrame({"제조업체명": vc_comp.index.tolist(), "건수": vc_comp.values.tolist()})
        def _draw_mini_table(bbox, title, headers, rows, col_widths=None, fs=8.8, title_align="left"):
            subax = fig2.add_axes(bbox, zorder=2)
            subax.set_facecolor("none")
            subax.patch.set_alpha(0.0)
            subax.axis("off")
            tx = 0.0 if title_align == "left" else 0.5
            ha = "left" if title_align == "left" else "center"
            subax.text(tx, 1.03, title, fontsize=10.4, weight="bold", va="bottom", ha=ha)
            if not rows:
                subax.text(0.5, 0.5, "표시할 정보가 없습니다.", ha="center", va="center", fontsize=9.0)
                return
            tblx = subax.table(
                cellText=rows,
                colLabels=headers,
                cellLoc="center",
                colLoc="center",
                colWidths=col_widths,
                bbox=[0, 0, 1, 0.94],
                loc="upper left",
            )
            tblx.auto_set_font_size(False)
            tblx.set_fontsize(fs)
            tblx.scale(1.0, 1.12)
            for (rr, cc), cell in tblx.get_celld().items():
                cell.set_text_props(ha="center", va="center", wrap=True)
                cell.set_facecolor((1, 1, 1, 0.0))
                if rr == 0:
                    cell.set_text_props(weight="bold")
                    cell.set_height(0.12)
                else:
                    cell.set_height(0.090 if len(rows) <= 8 else 0.076)
        detail_rows = [[_wrap_cell(str(r["세부구분"]), 15), int(r["건수"])] for _, r in detail_top_df.iterrows()]
        grade_rows = [[_wrap_cell(str(r["우선관리 등급"]), 14), int(r["업체 수"]), _wrap_cell(str(r.get("해당 업체명", "-")), 18)] for _, r in grade_company_df.iterrows()]
        company_rows = [[_wrap_cell(str(r["제조업체명"]), 14), int(r["건수"])] for _, r in company_top_df.iterrows()]
        _draw_mini_table([left2 + 0.03, bottom2 + 0.040, 0.23, 0.24], "지적사항 건수 Top 10 (회사)", ["제조업체명", "건수"], company_rows, [0.77, 0.23], fs=8.0, title_align="left")
        _draw_mini_table([left2 + 0.31, bottom2 + 0.040, 0.24, 0.24], "지적사항 건수 Top 10 (세부구분)", ["세부구분", "건수"], detail_rows, [0.74, 0.26], fs=8.3, title_align="left")
        _draw_mini_table([left2 + 0.57, bottom2 + 0.040, 0.36, 0.24], "우선관리 등급 별 업체 수", ["우선관리 등급", "업체 수", "해당 업체명"], grade_rows, [0.40, 0.15, 0.45], fs=7.8, title_align="left")
        _add_page_footer(fig2, 2)
        pdf.savefig(fig2)
        plt.close(fig2)
        # Page 3: existing graphs
        fig3 = plt.figure(figsize=a4_portrait)
