    hist_df.insert(0, 'No.', range(1, len(hist_df) + 1))
    st.markdown(_render_hover_html_table(hist_df, max_rows=None, max_widths={'No.':60, '실사기간':130, '등급':90, '세부구분':220, '지적사항 요약':620, '감시분야':120}, container_height=620), unsafe_allow_html=True)

